/* eslint-disable @typescript-eslint/no-magic-numbers */
import React from 'react';
import { isClient } from '@universe-design/react-utilities';
import { __SCREENSHOT__ } from '../util';

const MOCK_CURRENT_TIME = new Date(2021, 7, 23, 11, 23);

let mockDateCalledCount = 0;
const origDate = isClient() ? window.Date : undefined;

export function useMockDate(
  date: Date = MOCK_CURRENT_TIME,
  {
    skipped = !__SCREENSHOT__,
  }: {
    skipped?: boolean;
  } = {},
) {
  if (!skipped && !mockDateCalledCount && origDate) {
    window.Date = new Proxy(origDate, {
      construct(target: any, argArray: any[]): Date {
        if (argArray.length === 0) {
          return date;
        }
        return new target(...argArray);
      },
      get(target: any, prop: string | symbol, receiver: any): any {
        if (prop === 'now') {
          return () => date.getTime();
        }
        return Reflect.get(target, prop, receiver);
      },
    });
  }

  React.useEffect(() => {
    if (!skipped) {
      return;
    }
    mockDateCalledCount += 1;
    return () => {
      mockDateCalledCount--;
      if (!mockDateCalledCount && origDate) {
        window.Date = origDate;
      }
    };
  }, [skipped]);
}

export default function DateMocker(comp: React.ReactNode, date: Date = MOCK_CURRENT_TIME) {
  useMockDate(date);
  return comp;
}
